#!/usr/bin/env python3
"""Generate a .cc file embedding a binary as a byte array.

Usage: embed_binary.py <input-binary> <output.cc>
"""

import hashlib
import sys


def main() -> int:
    if len(sys.argv) != 3:
        print(__doc__, file=sys.stderr)
        return 2
    input_path, output_path = sys.argv[1], sys.argv[2]

    with open(input_path, "rb") as f:
        data = f.read()
    digest = hashlib.sha256(data).hexdigest()[:16]

    lines = [
        "// Generated by build/scripts/embed_binary.py -- do not edit.",
        "#include <cstddef>",
        "",
        "namespace kinglet {",
        "",
        "extern const unsigned char kEmbeddedCompilerData[];",
        "extern const std::size_t kEmbeddedCompilerSize;",
        "extern const char kEmbeddedCompilerHash[];",
        "",
        "const unsigned char kEmbeddedCompilerData[] = {",
    ]
    for i in range(0, len(data), 16):
        chunk = data[i : i + 16]
        lines.append("    " + ", ".join(str(b) for b in chunk) + ",")
    lines += [
        "};",
        "",
        "const std::size_t kEmbeddedCompilerSize = sizeof(kEmbeddedCompilerData);",
        f'const char kEmbeddedCompilerHash[] = "{digest}";',
        "",
        "} // namespace kinglet",
        "",
    ]

    with open(output_path, "w") as f:
        f.write("\n".join(lines))
    return 0


if __name__ == "__main__":
    sys.exit(main())
